'use client';

import React from 'react';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { SectionRenderer } from '@/lib/page-builder/section-renderer';

interface CanvasProps {
  sections: SectionConfig[];
  selectedSectionId: string | null;
  onSectionSelect: (sectionId: string) => void;
  onSectionDelete: (sectionId: string) => void;
  onSectionDuplicate: (sectionId: string) => void;
  previewMode: 'desktop' | 'tablet' | 'mobile';
  isPreview?: boolean;
}

export function Canvas({
  sections,
  selectedSectionId,
  onSectionSelect,
  onSectionDelete,
  onSectionDuplicate,
  previewMode,
  isPreview = false,
}: CanvasProps) {
  const getCanvasWidth = () => {
    switch (previewMode) {
      case 'mobile':
        return 'max-w-sm';
      case 'tablet':
        return 'max-w-2xl';
      default:
        return 'w-full';
    }
  };

  return (
    <div className="flex-1 overflow-auto bg-gray-100 dark:bg-gray-800 p-4">
      <div className={`mx-auto ${getCanvasWidth()} bg-white dark:bg-gray-900 shadow-lg rounded-lg overflow-hidden`}>
        {sections.length === 0 ? (
          <div className="p-16 text-center">
            <div className="text-6xl mb-4">🎨</div>
            <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
              Start Building Your Page
            </h3>
            <p className="text-gray-600 dark:text-gray-400">
              Drag sections from the library to start creating your page
            </p>
          </div>
        ) : (
          sections
            .sort((a, b) => a.order - b.order)
            .map((section) => (
              <SortableSection
                key={section.id}
                section={section}
                isSelected={selectedSectionId === section.id}
                onSelect={() => onSectionSelect(section.id)}
                onDelete={() => onSectionDelete(section.id)}
                onDuplicate={() => onSectionDuplicate(section.id)}
                isPreview={isPreview}
              />
            ))
        )}
      </div>
    </div>
  );
}

interface SortableSectionProps {
  section: SectionConfig;
  isSelected: boolean;
  onSelect: () => void;
  onDelete: () => void;
  onDuplicate: () => void;
  isPreview: boolean;
}

function SortableSection({
  section,
  isSelected,
  onSelect,
  onDelete,
  onDuplicate,
  isPreview,
}: SortableSectionProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: section.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.5 : 1,
  };

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={`relative group ${!isPreview ? 'cursor-pointer' : ''} ${
        isSelected && !isPreview ? 'ring-2 ring-blue-500 ring-offset-2' : ''
      }`}
      onClick={!isPreview ? onSelect : undefined}
    >
      <SectionRenderer
        section={section}
        isBuilder={!isPreview}
        isSelected={isSelected}
        onSelect={onSelect}
      />

      {/* Builder Controls */}
      {!isPreview && (
        <>
          {/* Drag Handle */}
          <div
            {...attributes}
            {...listeners}
            className={`absolute top-2 left-2 p-2 bg-white dark:bg-gray-800 rounded shadow-sm cursor-grab hover:bg-gray-50 dark:hover:bg-gray-700 transition-opacity ${
              isSelected ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
            }`}
          >
            <svg className="w-4 h-4 text-gray-600 dark:text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8h16M4 16h16" />
            </svg>
          </div>

          {/* Action Buttons */}
          <div className={`absolute top-2 right-2 flex space-x-1 transition-opacity ${
            isSelected ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'
          }`}>
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDuplicate();
              }}
              className="p-2 bg-white dark:bg-gray-800 rounded shadow-sm hover:bg-gray-50 dark:hover:bg-gray-700"
              title="Duplicate Section"
            >
              <svg className="w-4 h-4 text-gray-600 dark:text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
            </button>
            
            <button
              onClick={(e) => {
                e.stopPropagation();
                onDelete();
              }}
              className="p-2 bg-white dark:bg-gray-800 rounded shadow-sm hover:bg-red-50 dark:hover:bg-red-900/20 text-red-600 dark:text-red-400"
              title="Delete Section"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>
          </div>
        </>
      )}
    </div>
  );
}